css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0c0c0e; color: white; overflow-x: hidden; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 26px 60px; }
.brand { font-size: 24px; font-weight: 900; letter-spacing: 0.1em; }
.nav-links { display: flex; gap: 32px; }
.nav-links a { color: rgba(255,255,255,0.65); text-decoration: none; font-size: 13px; font-weight: 600; letter-spacing: 0.04em; text-transform: uppercase; }
.nav-icons { display: flex; gap: 18px; font-size: 18px; cursor: pointer; }
.hero { display: flex; align-items: center; justify-content: space-between; padding: 60px 60px 100px; gap: 60px; flex-wrap: wrap; }
.hero-text { max-width: 480px; }
.badge { display: inline-block; color: #f472b6; font-size: 12px; font-weight: 700; letter-spacing: 0.15em; margin-bottom: 24px; }
.hero-text h1 { font-size: 64px; font-weight: 900; line-height: 1.05; margin-bottom: 22px; text-transform: uppercase; }
.hero-text h1 span { color: #f472b6; }
.hero-text p { color: rgba(255,255,255,0.5); font-size: 15px; line-height: 1.7; margin-bottom: 30px; }
.btn-primary { background: white; color: #0c0c0e; border: none; padding: 16px 34px; font-size: 13px; font-weight: 800; letter-spacing: 0.08em; text-transform: uppercase; cursor: pointer; }
.hero-visual { position: relative; width: 320px; height: 380px; flex-shrink: 0; }
.img-block { border-radius: 4px; display: flex; align-items: center; justify-content: center; }
.img-main { width: 280px; height: 360px; background: linear-gradient(150deg, #1f1f24, #0c0c0e); border: 1px solid rgba(255,255,255,0.08); font-size: 90px; }
.img-small { position: absolute; bottom: -30px; right: -20px; width: 140px; height: 140px; background: linear-gradient(150deg, #f472b6, #ec4899); font-size: 50px; }
.categories { display: grid; grid-template-columns: repeat(3, 1fr); gap: 2px; padding: 0 60px 80px; }
.cat-card { aspect-ratio: 1; display: flex; flex-direction: column; justify-content: flex-end; padding: 28px; position: relative; }
.cat-1 { background: linear-gradient(150deg, #2a1a22, #0c0c0e); }
.cat-2 { background: linear-gradient(150deg, #1a1f2a, #0c0c0e); }
.cat-3 { background: linear-gradient(150deg, #1f1a2a, #0c0c0e); }
.cat-card h3 { font-size: 24px; font-weight: 800; text-transform: uppercase; margin-bottom: 4px; }
.cat-card p { color: rgba(255,255,255,0.45); font-size: 13px; margin-bottom: 16px; }
.cat-card button { background: transparent; border: none; color: white; font-size: 13px; font-weight: 700; cursor: pointer; align-self: flex-start; }
.products { padding: 60px; }
.products h2 { font-size: 32px; font-weight: 800; text-transform: uppercase; margin-bottom: 40px; text-align: center; }
.product-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 24px; max-width: 1100px; margin: 0 auto; }
.product-card { cursor: pointer; }
.product-img { aspect-ratio: 1; background: rgba(255,255,255,0.04); border-radius: 4px; display: flex; align-items: center; justify-content: center; font-size: 50px; margin-bottom: 14px; transition: 0.2s; }
.product-card:hover .product-img { background: rgba(244,114,182,0.1); }
.product-card h3 { font-size: 14px; font-weight: 700; margin-bottom: 6px; }
.price { color: rgba(255,255,255,0.5); font-size: 13px; font-weight: 600; }
.newsletter { text-align: center; padding: 80px 60px; background: linear-gradient(135deg, rgba(244,114,182,0.08), transparent); }
.newsletter h2 { font-size: 30px; font-weight: 800; text-transform: uppercase; margin-bottom: 12px; }
.newsletter p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 28px; }
.form-row { display: flex; gap: 12px; max-width: 420px; margin: 0 auto; }
.form-row input { flex: 1; padding: 15px 18px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-size: 14px; outline: none; }
.form-row input::placeholder { color: rgba(255,255,255,0.35); }
@media (max-width: 900px) { .hero { padding: 40px 24px; flex-direction: column; } .hero-text h1 { font-size: 42px; } .categories { grid-template-columns: 1fr; padding: 0 24px 50px; } .products, .newsletter { padding: 50px 24px; } }

js:
document.querySelectorAll('.product-card').forEach(card => {
  card.addEventListener('click', () => {
    const name = card.querySelector('h3').textContent;
    alert(`${name} sepete eklendi!`);
  });
});

document.querySelector('.form-row button').addEventListener('click', () => {
  const input = document.querySelector('.form-row input');
  if (input.value.includes('@')) {
    alert('Abonelik başarılı!');
    input.value = '';
  } else {
    alert('Geçerli bir e-posta girin.');
  }
});
